package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{Author: "Alice", Content: "This is a *great* comment!"},
	{Author: "Bob", Content: "I love **Go!**"},
	{Author: "Charlie", Content: "Hello _world_!"},
}

func commentHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `
	<!DOCTYPE html>
	<html lang="en">
	<head>
		<meta charset="UTF-8">
		<title>User Comments</title>
	</head>
	<body>
		<h1>User Comments</h1>
		<div>
			{{range .}}
				<p><strong>{{.Author}}</strong>: {{.Content | safeHTML}}</p>
			{{end}}
		</div>
	</body>
	</html>`
	t, err := template.New("comments").Funcs(template.FuncMap{
		"safeHTML": func(s string) template.HTML {
			return template.HTML(s) // Allows basic HTML formatting
		},
	}).Parse(tmpl)
	if err != nil {
		http.Error(w, "Error parsing template", http.StatusInternalServerError)
		return
	}
	t.Execute(w, comments)
}

func main() {
	http.HandleFunc("/comments", commentHandler)
	http.ListenAndServe(":8080", nil)
}